static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 2048;
static constexpr uint32_t HARD_CAP_ELEMS = 32768;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) { return (x / a) * a; }
static inline uint32_t CeilDiv(uint32_t a, uint32_t b) { return (a + b - 1u) / b; }

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    GemmBiasAddHardtanhMishGroupNormCustomTilingData tiling;

    const uint32_t batch = context->GetInputShape(0)->GetOriginShape().GetDim(0);
    const uint32_t inFeatures = context->GetInputShape(0)->GetOriginShape().GetDim(1);
    const uint32_t outFeatures = context->GetInputShape(1)->GetOriginShape().GetDim(0);

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int32_t *numGroups = attrs->GetAttrPointer<int32_t>(0);
    const float *epsilon = attrs->GetAttrPointer<float>(1);

    uint32_t totalElements = batch * outFeatures;

    // Each tile processes some number of samples.  We need per‑sample local storage:
    // - output of matmul: outFeatures floats
    // - workspace for group norm (uint8 buffer, estimate 4*outFeatures bytes is safe)
    // Roughly: outFeatures * 4 * 2 = 8*outFeatures bytes per sample
    uint32_t bytesPerSample = 8 * outFeatures;
    if (bytesPerSample == 0) bytesPerSample = 8; // guard
    uint32_t maxSamplesPerTile = UB_BUDGET_BYTES / bytesPerSample;
    if (maxSamplesPerTile < 1) maxSamplesPerTile = 1;
    const uint32_t tileBatch = maxSamplesPerTile;

    uint32_t tileLen = tileBatch * outFeatures; // elements per tile
    // Align tileLen to favour DMA
    tileLen = AlignDown(tileLen, ALIGN_ELEMS);
    if (tileLen == 0) tileLen = AlignDown(outFeatures, ALIGN_ELEMS);
    if (tileLen == 0) tileLen = outFeatures;

    const uint32_t numTiles = (tileLen == 0) ? 1 : CeilDiv(totalElements, tileLen);
    uint32_t blockDim = numTiles;
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;

    context->SetBlockDim(blockDim);

    tiling.set_totalLength(totalElements);
    tiling.set_tileLength(tileLen);
    tiling.set_blockDim(blockDim);
    tiling.set_batch(batch);
    tiling.set_inFeatures(inFeatures);
    tiling.set_outFeatures(outFeatures);
    tiling.set_numGroups(static_cast<uint32_t>(*numGroups));
    tiling.set_epsilon(*epsilon);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

